      let relativeErrorPercent;
      let message = `A \u2248 ${avgEstimate.toPrecision(8)} (promedio K=${K}, N=${N}) | \u03C3 repeticiones = ${stdDevK.toPrecision(6)} | rect area = ${rectArea.toPrecision(6)}`;
